// TypeScript 声明 for typo.css
// 消除 TypeScript 项目中的 "Cannot find module 'typo.css'" 错误
// 安装: npm install typo.css
// 使用: import "typo.css"

declare module "typo.css";

declare module "typo.css/reset";
declare module "typo.css/base";
declare module "typo.css/typography";
declare module "typo.css/code";
declare module "typo.css/table";
declare module "typo.css/forced-colors";
declare module "typo.css/reduced-data";
declare module "typo.css/utilities";
declare module "typo.css/rtl";
declare module "typo.css/print";
declare module "typo.css/theme-dark";
declare module "typo.css/theme-sepia";
declare module "typo.css/theme-contrast";
declare module "typo.css/theme-large";
